import os
import secrets
import json
from functools import wraps
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, request, session, jsonify, url_for
from jose import jwt
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.backends import default_backend
import base64

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://your-oidc-provider.com'),
    'authorization_endpoint': os.environ.get('OIDC_AUTH_ENDPOINT', 'https://your-oidc-provider.com/authorize'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT', 'https://your-oidc-provider.com/token'),
    'jwks_uri': os.environ.get('OIDC_JWKS_URI', 'https://your-oidc-provider.com/.well-known/jwks.json'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}

jwks_cache = None


def get_jwks():
    global jwks_cache
    if jwks_cache is None:
        response = requests.get(OIDC_CONFIG['jwks_uri'])
        jwks_cache = response.json()
    return jwks_cache


def generate_code_verifier():
    return base64.urlsafe_b64encode(secrets.token_bytes(32)).decode('utf-8').rstrip('=')


def generate_code_challenge(verifier):
    digest = hashes.Hash(hashes.SHA256(), backend=default_backend())
    digest.update(verifier.encode('utf-8'))
    return base64.urlsafe_b64encode(digest.finalize()).decode('utf-8').rstrip('=')


def generate_nonce():
    return secrets.token_urlsafe(32)


def hash_nonce(nonce):
    digest = hashes.Hash(hashes.SHA256(), backend=default_backend())
    digest.update(nonce.encode('utf-8'))
    return base64.urlsafe_b64encode(digest.finalize()).decode('utf-8')


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return jsonify({
            'message': 'Welcome!',
            'user': session['user']
        })
    return jsonify({'message': 'Please login', 'login_url': url_for('login')})


@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    nonce = generate_nonce()
    code_verifier = generate_code_verifier()
    code_challenge = generate_code_challenge(code_verifier)
    
    nonce_hash = hash_nonce(nonce)
    
    session['oauth_state'] = state
    session['nonce_hash'] = nonce_hash
    session['code_verifier'] = code_verifier
    session['original_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce,
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256'
    }
    
    authorization_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code or not state:
        return jsonify({'error': 'Missing code or state parameter'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    code_verifier = session.get('code_verifier')
    nonce_hash = session.get('nonce_hash')
    original_nonce = session.get('original_nonce')
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'code_verifier': code_verifier
    }
    
    token_response = requests.post(
        OIDC_CONFIG['token_endpoint'],
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )
    
    if token_response.status_code != 200:
        return jsonify({'error': 'Token exchange failed', 'details': token_response.text}), 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    
    if not id_token:
        return jsonify({'error': 'No id_token received'}), 400
    
    try:
        jwks = get_jwks()
        
        unverified_header = jwt.get_unverified_header(id_token)
        rsa_key = {}
        for key in jwks['keys']:
            if key['kid'] == unverified_header['kid']:
                rsa_key = {
                    'kty': key['kty'],
                    'kid': key['kid'],
                    'use': key['use'],
                    'n': key['n'],
                    'e': key['e']
                }
                break
        
        if not rsa_key:
            return jsonify({'error': 'Unable to find appropriate key'}), 400
        
        claims = jwt.decode(
            id_token,
            rsa_key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        token_nonce = claims.get('nonce')
        if not token_nonce:
            return jsonify({'error': 'No nonce in id_token'}), 400
        
        computed_hash = hash_nonce(token_nonce)
        if computed_hash != nonce_hash:
            return jsonify({'error': 'Nonce validation failed'}), 400
        
        if token_nonce != original_nonce:
            return jsonify({'error': 'Nonce mismatch'}), 400
        
        user_info = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'preferred_username': claims.get('preferred_username'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name')
        }
        
        session['user'] = user_info
        session['access_token'] = access_token
        session['id_token'] = id_token
        
        session.pop('oauth_state', None)
        session.pop('nonce_hash', None)
        session.pop('code_verifier', None)
        session.pop('original_nonce', None)
        
        return redirect(url_for('profile'))
        
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 400
    except jwt.JWTClaimsError as e:
        return jsonify({'error': 'Invalid claims', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Token validation failed', 'details': str(e)}), 400


@app.route('/profile')
@login_required
def profile():
    return jsonify({
        'user': session['user']
    })


@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


if __name__ == '__main__':
    app.run(debug=True, port=5000)